const input = $input.first().json;
const ZNUNY_URL = "https://ticket.doehlercomputing.de/znuny/nph-genericinterface.pl/Webservice/ZabbixIntegration";

// 1. Session
const session = await this.helpers.httpRequest({
  method: "POST", url: `${ZNUNY_URL}/Session`,
  body: {UserLogin: "zabbix", Password: "ZabbixInt3gration!"},
  json: true, skipSslCertificateValidation: true
});
if (!session.SessionID) {
  return [{json: {success: false, error: "Session failed: " + JSON.stringify(session)}}];
}

// 2. Update
const payload = {SessionID: session.SessionID, TicketID: input.ticket_id};
if (input.article) {
  payload.Article = {
    CommunicationChannel: "Internal", SenderType: "agent",
    Subject: input.article_subject || "N8N Incident Response",
    Body: input.article, ContentType: "text/plain; charset=utf-8"
  };
}
if (input.new_state) { payload.Ticket = {...(payload.Ticket||{}), State: input.new_state}; }
if (input.new_priority) { payload.Ticket = {...(payload.Ticket||{}), Priority: input.new_priority}; }

try {
  const result = await this.helpers.httpRequest({
    method: "PATCH", url: `${ZNUNY_URL}/Ticket/${input.ticket_id}`,
    body: payload, json: true, skipSslCertificateValidation: true
  });
  return [{json: {success: true, ticket_id: input.ticket_id, result}}];
} catch(e) {
  return [{json: {success: false, ticket_id: input.ticket_id, error: e.message}}];
}

